1	package device
2	
3	import (
4		"context"
5		"net/netip"
6		"sync"
7		"testing"
8		"time"
9	
10		"github.com/7mind/wanbond/internal/config"
11		"github.com/7mind/wanbond/internal/telemetry"
12	)
13	
14	// scriptedResolver is a hand-driven Resolver whose answer for a host can be changed between
15	// lookups (mutated under its lock), and which counts every Lookup call — enough to script a
16	// re-resolution's success/failure/empty timeline and to observe that an out-of-band lookup fired.
17	type scriptedResolver struct {
18		mu     sync.Mutex
19		answer map[string][]netip.Addr
20		ttl    time.Duration
21		ttlOk  bool
22		err    error // when non-nil, every Lookup returns it (simulates timeout/NXDOMAIN/transport error)
23		calls  int
24	}
25	
26	func newScriptedResolver() *scriptedResolver {
27		return &scriptedResolver{answer: map[string][]netip.Addr{}}
28	}
29	
30	func (s *scriptedResolver) Lookup(ctx context.Context, host string) ([]netip.Addr, time.Duration, bool, error) {
31		s.mu.Lock()
32		defer s.mu.Unlock()
33		s.calls++
34		if err := ctx.Err(); err != nil {
35			return nil, 0, false, err
36		}
37		if s.err != nil {
38			return nil, 0, false, s.err
39		}
40		return s.answer[host], s.ttl, s.ttlOk, nil
41	}
42	
43	func (s *scriptedResolver) set(host string, addrs ...netip.Addr) {
44		s.mu.Lock()
45		defer s.mu.Unlock()
46		s.answer[host] = addrs
47		s.err = nil
48	}
49	
50	func (s *scriptedResolver) fail(err error) {
51		s.mu.Lock()
52		defer s.mu.Unlock()
53		s.err = err
54	}
55	
56	func (s *scriptedResolver) empty(host string) {
57		s.mu.Lock()
58		defer s.mu.Unlock()
59		s.answer[host] = nil
60		s.err = nil
61	}
62	
63	func (s *scriptedResolver) callCount() int {
64		s.mu.Lock()
65		defer s.mu.Unlock()
66		return s.calls
67	}
68	
69	func mustAddr(t *testing.T, s string) netip.Addr {
70		t.Helper()
71		a, err := netip.ParseAddr(s)
72		if err != nil {
73			t.Fatalf("parse addr %q: %v", s, err)
74		}
75		return a
76	}
77	
78	// resolutionHarness wires a re-resolution controller over a real hubFailover built on fake
79	// health/remote/clock, so a repoint is observable through the recording remote exactly as
80	// production drives it through updateResolution.
81	type resolutionHarness struct {
82		res  *resolution
83		fo   *hubFailover
84		rem  *recordingRemote
85		rslv *scriptedResolver
86		clk  *fakeClock
87		hp   []*fakeHealth
88	}
89	
90	const (
91		testPollInterval = 30 * time.Second
92		testDNSTimeout   = 5 * time.Second
93	)
94	
95	// newResolutionHarness builds the controller for a single active hostname spec (spec 0) plus a
96	// literal standby (spec 1). The active hostname is pre-seeded with initialActive so activeSpec is
97	// already set (no boot adoption noise) unless initialActive is the zero value.
98	func newResolutionHarness(t *testing.T, host string, port uint16, initialActive netip.AddrPort, health ...telemetry.PathState) *resolutionHarness {
99		t.Helper()
100		var initAddrs []netip.AddrPort
101		if initialActive != (netip.AddrPort{}) {
102			initAddrs = []netip.AddrPort{initialActive}
103		}
104		specs := []failoverSpec{
105			{spec: config.EndpointSpec{Host: host, Port: port, IsName: true}, addrs: initAddrs},
106			litSpec(t, "198.51.100.7:51820"),
107		}
108		hp := make([]*fakeHealth, len(health))
109		hh := make([]hubHealth, len(health))
110		for i, st := range health {
111			hp[i] = &fakeHealth{st}
112			hh[i] = hp[i]
113		}
114		rem := &recordingRemote{}
115		clk := &fakeClock{now: time.Unix(1000, 0)}
116		fo := newHubFailoverFromSpecs(specs, hh, rem, func() {}, clk, testSettle, discardLogger(t))
117		rslv := newScriptedResolver()
118		res := newResolution(rslv, fo, nameTargetsFromSpecs([]config.EndpointSpec{
119			{Host: host, Port: port, IsName: true},
120			{Addr: mustAP(t, "198.51.100.7:51820")},
121		}), clk, testPollInterval, testDNSTimeout, discardLogger(t))
122		return &resolutionHarness{res: res, fo: fo, rem: rem, rslv: rslv, clk: clk, hp: hp}
123	}
124	
125	// advancePastPoll advances the fake clock beyond the next scheduled poll so the following step
126	// performs a full poll.
127	func (h *resolutionHarness) advancePastPoll() {
128		h.clk.advance(testPollInterval + time.Second)
129	}
130	
131	// TestResolutionLookupFailureRetainsAndRetries is acceptance (1) + the D46 error case: a lookup
132	// that FAILS at every tick leaves the endpoint set untouched (no SetPeerRemote), never hard-fails,
133	// and keeps retrying — the resolver is called once per poll.
134	func TestResolutionLookupFailureRetainsAndRetries(t *testing.T) {
135		host := "hub.example.com"
136		active := mustAP(t, "203.0.113.1:51820")
137		h := newResolutionHarness(t, host, 51820, active, telemetry.StateUp)
138		h.rslv.fail(context.DeadlineExceeded)
139	
140		for i := 0; i < 8; i++ {
141			h.advancePastPoll()
142			h.res.step()
143		}
144	
145		if h.rem.calls != 0 {
146			t.Fatalf("lookup failure repointed the bond %d times, want 0 (retention: keep last-good)", h.rem.calls)
147		}
148		if h.fo.activeSpec != 0 || h.fo.activeAddr != active {
149			t.Fatalf("active endpoint moved to (%d,%v) under lookup failure, want (0,%v) untouched", h.fo.activeSpec, h.fo.activeAddr, active)
150		}
151		if got := len(h.fo.specs[0].addrs); got != 1 || h.fo.specs[0].addrs[0] != active {
152			t.Fatalf("active spec expansion = %v under lookup failure, want [%v] retained", h.fo.specs[0].addrs, active)
153		}
154		// Retries kept happening: one lookup per poll tick (8 ticks).
155		if got := h.rslv.callCount(); got < 8 {
156			t.Fatalf("resolver called %d times over 8 poll ticks, want >= 8 (kept retrying)", got)
157		}
158	}
159	
160	// TestResolutionChangedActiveIPRepointsOnce is acceptance (2): a changed active IP produces
161	// EXACTLY one SetPeerRemote — the repoint — even across many subsequent ticks returning the same
162	// new IP (D32 suppression inside updateResolution).
163	func TestResolutionChangedActiveIPRepointsOnce(t *testing.T) {
164		host := "hub.example.com"
165		oldA := mustAP(t, "203.0.113.1:51820")
166		newAddr := mustAddr(t, "203.0.113.2")
167		newAP := netip.AddrPortFrom(newAddr, 51820)
168		h := newResolutionHarness(t, host, 51820, oldA, telemetry.StateUp)
169		h.rslv.set(host, newAddr)
170	
171		for i := 0; i < 6; i++ {
172			h.advancePastPoll()
173			h.res.step()
174		}
175	
176		if h.rem.calls != 1 {
177			t.Fatalf("changed active IP produced %d SetPeerRemote, want exactly 1", h.rem.calls)
178		}
179		if h.rem.last != newAP {
180			t.Fatalf("repointed remote = %v, want new active record %v", h.rem.last, newAP)
181		}
182		if h.fo.activeAddr != newAP {
183			t.Fatalf("active addr = %v, want %v", h.fo.activeAddr, newAP)
184		}
185	}
186	
187	// TestResolutionUnchangedIPNoRepoint is acceptance (3): an unchanged IP produces NO SetPeerRemote
188	// over many ticks.
189	func TestResolutionUnchangedIPNoRepoint(t *testing.T) {
190		host := "hub.example.com"
191		active := mustAP(t, "203.0.113.1:51820")
192		h := newResolutionHarness(t, host, 51820, active, telemetry.StateUp)
193		h.rslv.set(host, active.Addr())
194	
195		for i := 0; i < 20; i++ {
196			h.advancePastPoll()
197			h.res.step()
198		}
199	
200		if h.rem.calls != 0 {
201			t.Fatalf("unchanged IP produced %d SetPeerRemote over 20 ticks, want 0", h.rem.calls)
202		}
203		if h.fo.activeSpec != 0 || h.fo.activeAddr != active {
204			t.Fatalf("active endpoint drifted to (%d,%v), want (0,%v)", h.fo.activeSpec, h.fo.activeAddr, active)
205		}
206	}
207	
208	// TestResolutionAllDownTriggersOutOfBandReResolve is acceptance (4): when every path to the
209	// active endpoint goes DOWN, an out-of-band re-resolve of the active spec fires BEFORE the next
210	// scheduled poll tick — observable both as an extra resolver Lookup while the poll is NOT yet due
211	// and, since the answer changed, as an immediate repoint.
212	func TestResolutionAllDownTriggersOutOfBandReResolve(t *testing.T) {
213		host := "hub.example.com"
214		oldA := mustAP(t, "203.0.113.1:51820")
215		newAddr := mustAddr(t, "203.0.113.2")
216		newAP := netip.AddrPortFrom(newAddr, 51820)
217		h := newResolutionHarness(t, host, 51820, oldA, telemetry.StateUp, telemetry.StateUp)
218		h.rslv.set(host, oldA.Addr())
219	
220		// One step with paths UP: records the not-down baseline (edge detection) and consumes the
221		// initial scheduled poll (unchanged IP → no repoint).
222		h.advancePastPoll()
223		h.res.step()
224		if h.rem.calls != 0 {
225			t.Fatalf("baseline step repointed %d times, want 0", h.rem.calls)
226		}
227		callsBefore := h.rslv.callCount()
228	
229		// The DNS answer changes AND every path goes DOWN. WITHOUT advancing the clock (poll is not
230		// due), a step must still re-resolve the active spec out of band and repoint.
231		h.rslv.set(host, newAddr)
232		h.hp[0].state = telemetry.StateDown
233		h.hp[1].state = telemetry.StateDown
234		h.res.step()
235	
236		if got := h.rslv.callCount(); got != callsBefore+1 {
237			t.Fatalf("out-of-band re-resolve made %d lookups, want exactly 1 before the next poll tick", got-callsBefore)
238		}
239		if h.rem.calls != 1 || h.rem.last != newAP {
240			t.Fatalf("liveness-loss re-resolve repoint = (calls %d, last %v), want (1, %v)", h.rem.calls, h.rem.last, newAP)
241		}
242	
243		// Edge-triggered: a second step while still all-down (no new edge) does NOT re-resolve again.
244		callsAfter := h.rslv.callCount()
245		h.res.step()
246		if got := h.rslv.callCount(); got != callsAfter {
247			t.Fatalf("all-down re-resolve fired again on a level (non-edge) tick: %d extra lookups, want 0", got-callsAfter)
248		}
249	}
250	
251	// TestResolutionTTLClampShortensNextDelay is acceptance (5): a TTL below the poll interval
252	// shortens the next resolve delay to that TTL; a TTL at or above it (or an absent TTL) leaves the
253	// poll interval unchanged.
254	func TestResolutionTTLClampShortensNextDelay(t *testing.T) {
255		host := "hub.example.com"
256		active := mustAP(t, "203.0.113.1:51820")
257		h := newResolutionHarness(t, host, 51820, active, telemetry.StateUp)
258		h.rslv.set(host, active.Addr())
259	
260		// TTL (5s) below the poll interval (30s): next delay clamps to the TTL.
261		h.rslv.ttl = 5 * time.Second
262		h.rslv.ttlOk = true
263		if got := h.res.pollAll(); got != 5*time.Second {
264			t.Fatalf("pollAll next delay = %v with a 5s TTL, want 5s (clamped to TTL)", got)
265		}
266	
267		// TTL absent (system resolver, ttlOk=false): next delay is the full poll interval.
268		h.rslv.ttlOk = false
269		if got := h.res.pollAll(); got != testPollInterval {
270			t.Fatalf("pollAll next delay = %v with no TTL, want %v (poll interval)", got, testPollInterval)
271		}
272	
273		// TTL (60s) above the poll interval: not shortened below the interval.
274		h.rslv.ttl = 60 * time.Second
275		h.rslv.ttlOk = true
276		if got := h.res.pollAll(); got != testPollInterval {
277			t.Fatalf("pollAll next delay = %v with a 60s TTL, want %v (interval, not lengthened)", got, testPollInterval)
278		}
279	}
280	
281	// TestResolutionEmptyResultRetainsLastGood is the D46 acceptance: a lookup returning an EMPTY /
282	// NXDOMAIN result for a PREVIOUSLY-resolved hostname retains the last-good expansion — the
283	// controller never publishes an empty set, so hubFailover never sees the active spec collapse to
284	// empty (the condition that could strand the bond under its total<2 guard).
285	func TestResolutionEmptyResultRetainsLastGood(t *testing.T) {
286		host := "hub.example.com"
287		active := mustAP(t, "203.0.113.1:51820")
288		h := newResolutionHarness(t, host, 51820, active, telemetry.StateUp)
289	
290		// First: a good answer keeps the previously-resolved record in place (unchanged → no repoint).
291		h.rslv.set(host, active.Addr())
292		h.advancePastPoll()
293		h.res.step()
294		if got := len(h.fo.specs[0].addrs); got != 1 || h.fo.specs[0].addrs[0] != active {
295			t.Fatalf("after good lookup, active spec = %v, want [%v]", h.fo.specs[0].addrs, active)
296		}
297	
298		// Now the resolver goes NODATA/NXDOMAIN (empty). The last-good record MUST be retained.
299		h.rslv.empty(host)
300		for i := 0; i < 5; i++ {
301			h.advancePastPoll()
302			h.res.step()
303		}
304	
305		if got := len(h.fo.specs[0].addrs); got != 1 || h.fo.specs[0].addrs[0] != active {
306			t.Fatalf("empty/NXDOMAIN result collapsed the active spec to %v, want [%v] retained (D46)", h.fo.specs[0].addrs, active)
307		}
308		if h.rem.calls != 0 {
309			t.Fatalf("empty result touched the bond %d times, want 0 (never publish empty)", h.rem.calls)
310		}
311		if h.fo.activeSpec != 0 || h.fo.activeAddr != active {
312			t.Fatalf("active identity = (%d,%v) after empty result, want (0,%v)", h.fo.activeSpec, h.fo.activeAddr, active)
313		}
314	}
315	
316	// TestResolutionSingleHostnameBootAdopts proves the controller runs even for a SINGLE-hostname
317	// peer (independent of hub-failover's >=2 guard): the sole spec boots EMPTY (activeSpec == -1),
318	// and the first successful poll publishes the resolved head, which updateResolution adopts as the
319	// active endpoint via exactly one SetPeerRemote.
320	func TestResolutionSingleHostnameBootAdopts(t *testing.T) {
321		host := "hub.example.com"
322		first := mustAddr(t, "203.0.113.1")
323		firstAP := netip.AddrPortFrom(first, 51820)
324		specs := []failoverSpec{
325			{spec: config.EndpointSpec{Host: host, Port: 51820, IsName: true}}, // sole spec, EMPTY at boot
326		}
327		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
328		rem := &recordingRemote{}
329		clk := &fakeClock{now: time.Unix(1000, 0)}
330		fo := newHubFailoverFromSpecs(specs, hp, rem, func() {}, clk, testSettle, discardLogger(t))
331		if fo.activeSpec != -1 {
332			t.Fatalf("single hostname boot activeSpec = %d, want -1 (empty)", fo.activeSpec)
333		}
334		rslv := newScriptedResolver()
335		rslv.set(host, first)
336		res := newResolution(rslv, fo, nameTargetsFromSpecs([]config.EndpointSpec{
337			{Host: host, Port: 51820, IsName: true},
338		}), clk, testPollInterval, testDNSTimeout, discardLogger(t))
339	
340		// First step polls immediately (nextPollAt armed at construction time) and adopts.
341		res.step()
342	
343		if rem.calls != 1 || rem.last != firstAP {
344			t.Fatalf("single-hostname boot adoption SetPeerRemote = (calls %d, last %v), want (1, %v)", rem.calls, rem.last, firstAP)
345		}
346		if fo.activeSpec != 0 || fo.activeAddr != firstAP {
347			t.Fatalf("post-adoption active = (%d,%v), want (0,%v)", fo.activeSpec, fo.activeAddr, firstAP)
348		}
349	}
350	
351	// TestOrderAddrPortsDeterministicFamilyOrder pins the ordering contract orderAddrPorts must hold
352	// for updateResolution's suppression to work: IPv4 first (resolver order), then IPv6, deduped,
353	// 4in6 canonicalized — byte-identical across identical answers.
354	func TestOrderAddrPortsDeterministicFamilyOrder(t *testing.T) {
355		in := []netip.Addr{
356			mustAddr(t, "2001:db8::2"),
357			mustAddr(t, "203.0.113.1"),
358			mustAddr(t, "2001:db8::1"),
359			mustAddr(t, "203.0.113.1"), // duplicate v4 → dropped
360			mustAddr(t, "203.0.113.2"),
361		}
362		got := orderAddrPorts(in, 51820)
363		want := []netip.AddrPort{
364			netip.AddrPortFrom(mustAddr(t, "203.0.113.1"), 51820),
365			netip.AddrPortFrom(mustAddr(t, "203.0.113.2"), 51820),
366			netip.AddrPortFrom(mustAddr(t, "2001:db8::2"), 51820),
367			netip.AddrPortFrom(mustAddr(t, "2001:db8::1"), 51820),
368		}
369		if len(got) != len(want) {
370			t.Fatalf("orderAddrPorts len = %d (%v), want %d (%v)", len(got), got, len(want), want)
371		}
372		for i := range want {
373			if got[i] != want[i] {
374				t.Fatalf("orderAddrPorts[%d] = %v, want %v (v4-first, resolver order, deduped)", i, got[i], want[i])
375			}
376		}
377	}
